mapper.select:
SELECT rd.id, rd.reservation_id, rd.device_id, rd.device_order, rd.created_at FROM reservation_device rd WHERE rd.reservation_id IN
#{reservationId}
ORDER BY rd.reservation_id ASC, rd.device_order ASC, rd.created_at ASC

SELECT 
FROM reservation r

WHERE 1 = 1

      AND r.user_id = #{userId}

ORDER BY r.created_at DESC, r.start_time DESC
LIMIT #{limit} OFFSET #{offset}

SELECT 
FROM reservation r

WHERE (
        EXISTS (
            SELECT 1
            FROM reservation_device rd
            WHERE rd.reservation_id = r.id
              AND rd.device_id = #{deviceId}
        )
        OR (
            NOT EXISTS (
                SELECT 1
                FROM reservation_device rd
                WHERE rd.reservation_id = r.id
            )
            AND r.device_id = #{deviceId}
        )
    )
  AND r.status IN ('PENDING_DEVICE_APPROVAL', 'PENDING_SYSTEM_APPROVAL', 'PENDING_MANUAL', 'APPROVED')
  AND r.start_time < #{endTime}
  AND r.end_time > #{startTime}

SELECT COUNT(1)
FROM reservation r
WHERE (
        EXISTS (
            SELECT 1
            FROM reservation_device rd
            WHERE rd.reservation_id = r.id
              AND rd.device_id = #{deviceId}
        )
        OR (
            NOT EXISTS (
                SELECT 1
                FROM reservation_device rd
                WHERE rd.reservation_id = r.id
            )
            AND r.device_id = #{deviceId}
        )
    )
  AND r.status IN ('PENDING_DEVICE_APPROVAL', 'PENDING_SYSTEM_APPROVAL', 'PENDING_MANUAL', 'APPROVED')
  AND r.start_time < #{endTime}
  AND r.end_time > #{startTime}

mapper.update:
UPDATE reservation
SET status = 'CANCELLED',
    cancel_reason = #{cancelReason},
    cancel_time = #{cancelTime},
    updated_at = #{updatedAt}
WHERE id = #{reservationId}
  AND status IN

      #{status}

  AND sign_status = 'NOT_CHECKED_IN'
  AND checked_in_at IS NULL
  AND start_time > #{currentTime}

mapper.select:
SELECT 
FROM reservation r

WHERE r.status = 'APPROVED'
  AND r.start_time >= #{start}
  AND r.start_time <= #{end}

SELECT 
FROM reservation r

WHERE (
        EXISTS (
            SELECT 1
            FROM reservation_device rd
            WHERE rd.reservation_id = r.id
              AND rd.device_id = #{deviceId}
        )
        OR (
            NOT EXISTS (
                SELECT 1
                FROM reservation_device rd
                WHERE rd.reservation_id = r.id
            )
            AND r.device_id = #{deviceId}
        )
    )
  AND r.status = 'APPROVED'
  AND r.start_time >= #{start}
ORDER BY r.start_time ASC
